from policyengine_us import Simulation
def snap_m(size, earned=0, rent=0, state="CA", ages=None, period="2026-06"):
    yr=period[:4]
    members=[f"p{i}" for i in range(size)]
    people={}
    for i,m in enumerate(members):
        a=(ages[i] if ages else (30 if i==0 else 5))
        people[m]={"age":{yr:a}}
        if i==0 and earned: people[m]["employment_income"]={period:earned}
    spm={"members":members,"snap":{period:None}}
    if rent: spm["housing_cost"]={period:rent}
    sit={"people":people,"spm_units":{"s":spm},
      "households":{"h":{"members":members,"state_name":{yr:state}}}}
    return float(Simulation(situation=sit).calculate("snap",period)[0])
print("MONTHLY max allotment (zero income), period 2026-06:")
for n in range(1,9): print(f"  {n}: {round(snap_m(n),2)}")
print("3p $2000/mo earned, rent $1500:", round(snap_m(3,2000,1500),2))
PY
